From 88d89d6523802c044cfcb7930cba40d8eeb21da2 Mon Sep 17 00:00:00 2001
From: juanpablo <juanpablo@apache.org>
Date: Thu, 21 Mar 2019 23:06:20 +0100
Subject: [PATCH] JSPWIKI-1095: DefaultURLConstructor#getForwardPage(
 HttpServletRequest req ) now always returns "Wiki.jsp"


diff --git a/jspwiki-main/src/main/java/org/apache/wiki/url/DefaultURLConstructor.java b/jspwiki-main/src/main/java/org/apache/wiki/url/DefaultURLConstructor.java
index 7d596b8a1..4404f42b7 100644
--- a/jspwiki-main/src/main/java/org/apache/wiki/url/DefaultURLConstructor.java
+++ b/jspwiki-main/src/main/java/org/apache/wiki/url/DefaultURLConstructor.java
@@ -277,6 +277,6 @@ public class DefaultURLConstructor
      */
     public String getForwardPage( HttpServletRequest request )
     {
-        return request.getPathInfo();
+        return "Wiki.jsp";
     }
 }

